import React, { useCallback } from "react";
import Particles from "react-tsparticles";
import { loadFull } from "tsparticles";

const NetworkBackground = () => {
    const particlesInit = useCallback(async (engine) => {
        // you must initialize the tsParticles instance (engine) here, adding custom shapes or presets
        // this loads the tsparticles package bundle, it's the easiest method for getting everything ready
        // starting from v2 you can add only the features you need reducing the bundle size
        await loadFull(engine);
    }, []);

    const particlesLoaded = useCallback(async (container) => {
        // await console.log(container);
    }, []);

    return (
        <Particles
            id="tsparticles"
            init={particlesInit}
            loaded={particlesLoaded}
            className="fixed inset-0 z-0 pointer-events-none"
            options={{
                fullScreen: { enable: false, zIndex: 0 },
                background: {
                    color: {
                        value: "transparent",
                    },
                },
                fpsLimit: 120,
                interactivity: {
                    events: {
                        onHover: {
                            enable: true,
                            mode: "grab",
                        },
                        resize: true,
                    },
                    modes: {
                        grab: {
                            distance: 140,
                            links: {
                                opacity: 1,
                                color: "#6366f1"
                            }
                        },
                    },
                },
                particles: {
                    color: {
                        value: "#3f3f46", // zinc-700
                    },
                    links: {
                        color: "#27272a", // zinc-800
                        distance: 150,
                        enable: true,
                        opacity: 0.5,
                        width: 1,
                    },
                    move: {
                        direction: "none",
                        enable: true,
                        outModes: {
                            default: "bounce",
                        },
                        random: false,
                        speed: 0.5,
                        straight: false,
                    },
                    number: {
                        density: {
                            enable: true,
                            area: 800,
                        },
                        value: 40,
                    },
                    opacity: {
                        value: 0.5,
                    },
                    shape: {
                        type: "circle",
                    },
                    size: {
                        value: { min: 1, max: 3 },
                    },
                },
                detectRetina: true,
            }}
        />
    );
};

export default NetworkBackground;

import React from 'react';
import { motion } from 'framer-motion';

const pageVariants = {
  initial: {
    opacity: 0,
    y: 10,
  },
  in: {
    opacity: 1,
    y: 0,
  },
  out: {
    opacity: 0,
    y: -10,
  },
};

const pageTransition = {
  type: 'tween',
  ease: 'anticipate',
  duration: 0.5,
};

const PageTransition = ({ children }) => {
  return (
    <motion.div
      initial="initial"
      animate="in"
      exit="out"
      variants={pageVariants}
      transition={pageTransition}
      className="page-wrapper"
    >
      {children}
    </motion.div>
  );
};

export default PageTransition;

import React, { useState } from 'react';
import { motion } from 'framer-motion';
import { Send, CheckCircle2, FlaskConical, Github, Linkedin, Mail, Cpu } from 'lucide-react';
import PageTransition from '../components/PageTransition';

const Collaboration = () => {
  const [formData, setFormData] = useState({
    name: '',
    email: '',
    projectType: 'General Inquiry',
    message: ''
  });
  const [status, setStatus] = useState({ loading: false, error: null, success: false });

  const handleChange = (e) => {
    setFormData({ ...formData, [e.target.name]: e.target.value });
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setStatus({ loading: true, error: null, success: false });

    try {
      const response = await fetch('http://localhost:5000/api/contact', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(formData)
      });

      const data = await response.json();

      if (response.ok) {
        setStatus({ loading: false, error: null, success: true });
        setFormData({ name: '', email: '', projectType: 'General Inquiry', message: '' });
        setTimeout(() => setStatus(prev => ({ ...prev, success: false })), 5000);
      } else {
        setStatus({ loading: false, error: data.message || 'Failed to send message.', success: false });
      }
    } catch (err) {
      console.error(err);
      setStatus({ loading: false, error: 'Network error. Please make sure the backend is running.', success: false });
    }
  };

  return (
    <PageTransition>
      <div className="pt-24 pb-20 min-h-screen relative z-10">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">

          <div className="mb-16 mt-12 text-center max-w-3xl mx-auto">
            <div className="inline-flex items-center gap-2 px-3 py-1.5 rounded border border-indigo-500/30 bg-indigo-500/10 text-indigo-400 text-xs font-mono mb-6">
              <Cpu size={14} />
              OPEN FOR COLLABORATION
            </div>
            <h1 className="text-5xl md:text-7xl font-heading font-extrabold mb-6 text-white tracking-tight">Initiate <span className="text-indigo-400">Connection</span></h1>
            <p className="text-lg text-zinc-400 font-mono">
              Seeking opportunities to merge Deep Learning architectures with scalable Android and Full-Stack systems.
            </p>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-5 gap-12 lg:gap-8 items-start">

            {/* Future Research Pitch (Left Col - 2 spans) */}
            <div className="lg:col-span-2 space-y-8">
              <div className="bg-zinc-900 border border-zinc-800 p-8 rounded-2xl relative overflow-hidden group">
                <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity">
                  <FlaskConical size={100} />
                </div>

                <h3 className="text-2xl font-heading font-bold text-white mb-6 relative z-10">Future Research Interests</h3>
                <div className="space-y-6 relative z-10">
                  <div className="flex gap-4 items-start">
                    <span className="w-6 h-6 rounded flex items-center justify-center bg-indigo-500/20 text-indigo-400 font-mono text-xs shrink-0 mt-1">01</span>
                    <p className="text-zinc-300 text-sm leading-relaxed">
                      <strong className="text-white">Edge AI & Mobile:</strong> Optimizing quantized NLP and Vision models for on-device execution in Android ecosystems via Kotlin and Jetpack Compose.
                    </p>
                  </div>
                  <div className="flex gap-4 items-start">
                    <span className="w-6 h-6 rounded flex items-center justify-center bg-purple-500/20 text-purple-400 font-mono text-xs shrink-0 mt-1">02</span>
                    <p className="text-zinc-300 text-sm leading-relaxed">
                      <strong className="text-white">Intelligent Data Pipelines:</strong> Building scalable MERN architectures that natively interface with Python-driven algorithmic engines.
                    </p>
                  </div>
                  <div className="flex gap-4 items-start">
                    <span className="w-6 h-6 rounded flex items-center justify-center bg-emerald-500/20 text-emerald-400 font-mono text-xs shrink-0 mt-1">03</span>
                    <p className="text-zinc-300 text-sm leading-relaxed">
                      <strong className="text-white">Predictive Health & Web3:</strong> Exploring intersectional spaces where predictive modeling can secure decentralized data points.
                    </p>
                  </div>
                </div>
              </div>

              {/* Direct Links */}
              <div className="flex flex-col gap-4">
                <a href="https://linkedin.com/in/prachi-dhiman05/" target="_blank" rel="noreferrer" className="flex items-center justify-between p-4 bg-zinc-900 border border-zinc-800 rounded-xl hover:border-indigo-500 hover:bg-indigo-500/10 transition-all group">
                  <div className="flex items-center gap-3">
                    <Linkedin className="text-indigo-400" />
                    <span className="font-heading font-bold text-white">LinkedIn Network</span>
                  </div>
                  <span className="text-xs font-mono text-zinc-500 group-hover:text-indigo-400">Connect &rarr;</span>
                </a>
                <a href="https://github.com/PrachiDhiman5" target="_blank" rel="noreferrer" className="flex items-center justify-between p-4 bg-zinc-900 border border-zinc-800 rounded-xl hover:border-zinc-500 hover:bg-zinc-800 transition-all group">
                  <div className="flex items-center gap-3">
                    <Github className="text-zinc-300" />
                    <span className="font-heading font-bold text-white">GitHub Modules</span>
                  </div>
                  <span className="text-xs font-mono text-zinc-500 group-hover:text-zinc-300">Inspect &rarr;</span>
                </a>
              </div>
            </div>

            {/* Contact Form (Right Col - 3 spans) */}
            <div className="lg:col-span-3">
              <div className="bg-zinc-950 border border-zinc-800 rounded-2xl p-8 md:p-10 shadow-2xl relative">

                <h3 className="text-2xl font-heading font-bold mb-8 text-white flex items-center gap-3">
                  <Mail className="text-zinc-500" /> System Access Request
                </h3>

                {status.success ? (
                  <motion.div 
                    initial={{ opacity: 0, scale: 0.95 }}
                    animate={{ opacity: 1, scale: 1 }}
                    className="flex flex-col items-center justify-center py-16 text-center space-y-4"
                  >
                    <CheckCircle2 size={64} className="text-indigo-500 mb-2" />
                    <h3 className="text-2xl font-heading font-bold text-white">Transmission Received</h3>
                    <p className="text-zinc-400 font-mono text-sm max-w-sm">
                      Your query has been securely transmitted. I will parse the data and respond shortly.
                    </p>
                  </motion.div>
                ) : (
                  <form onSubmit={handleSubmit} className="space-y-6">
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-6">
                      <div className="space-y-2">
                        <label htmlFor="name" className="text-xs font-mono text-zinc-400 uppercase tracking-widest block">Indentification</label>
                        <input
                          type="text"
                          id="name"
                          name="name"
                          value={formData.name}
                          onChange={handleChange}
                          required
                          placeholder="Your Name"
                          className="w-full bg-zinc-900 border border-zinc-700 rounded-lg px-4 py-3 text-white placeholder:text-zinc-600 focus:outline-none focus:border-indigo-500 focus:ring-1 focus:ring-indigo-500 transition-all font-mono text-sm"
                        />
                      </div>
                      <div className="space-y-2">
                        <label htmlFor="email" className="text-xs font-mono text-zinc-400 uppercase tracking-widest block">Return Address</label>
                        <input
                          type="email"
                          id="email"
                          name="email"
                          value={formData.email}
                          onChange={handleChange}
                          required
                          placeholder="your.email@domain.com"
                          className="w-full bg-zinc-900 border border-zinc-700 rounded-lg px-4 py-3 text-white placeholder:text-zinc-600 focus:outline-none focus:border-indigo-500 focus:ring-1 focus:ring-indigo-500 transition-all font-mono text-sm"
                        />
                      </div>
                    </div>

                    <div className="space-y-2">
                      <label htmlFor="projectType" className="text-xs font-mono text-zinc-400 uppercase tracking-widest block">Project Classification</label>
                      <select
                        id="projectType"
                        name="projectType"
                        value={formData.projectType}
                        onChange={handleChange}
                        className="w-full bg-zinc-900 border border-zinc-700 rounded-lg px-4 py-3 text-white focus:outline-none focus:border-indigo-500 focus:ring-1 focus:ring-indigo-500 transition-all font-mono text-sm appearance-none cursor-pointer"
                        style={{ backgroundImage: `url("data:image/svg+xml,%3csvg xmlns='http://www.w3.org/2000/svg' fill='none' viewBox='0 0 20 20'%3e%3cpath stroke='%236b7280' stroke-linecap='round' stroke-linejoin='round' stroke-width='1.5' d='M6 8l4 4 4-4'/%3e%3c/svg%3e")`, backgroundPosition: `right 0.5rem center`, backgroundRepeat: `no-repeat`, backgroundSize: `1.5em 1.5em`, paddingRight: `2.5rem` }}
                      >
                        <option value="General Inquiry">General Inquiry</option>
                        <option value="Machine Learning / AI Pipeline">Machine Learning / AI Pipeline</option>
                        <option value="Full-Stack Web Development">Full-Stack Web Development</option>
                        <option value="Android Mobile App">Android Mobile App</option>
                        <option value="Data Analytics / Visualization">Data Analytics / Visualization</option>
                      </select>
                    </div>

                    <div className="space-y-2">
                      <label htmlFor="message" className="text-xs font-mono text-zinc-400 uppercase tracking-widest block">Payload</label>
                      <textarea
                        id="message"
                        name="message"
                        value={formData.message}
                        onChange={handleChange}
                        required
                        rows="5"
                        placeholder="Describe the architecture, problem set, or collaborative proposal..."
                        className="w-full bg-zinc-900 border border-zinc-700 rounded-lg px-4 py-3 text-white placeholder:text-zinc-600 focus:outline-none focus:border-indigo-500 focus:ring-1 focus:ring-indigo-500 transition-all font-mono text-sm resize-none custom-scrollbar"
                      ></textarea>
                    </div>

                    {status.error && (
                      <div className="p-4 bg-red-900/20 border border-red-500/50 rounded-lg text-red-400 text-sm font-mono">
                        ERR: {status.error}
                      </div>
                    )}

                    <button
                      type="submit"
                      disabled={status.loading}
                      className="w-full py-4 bg-white hover:bg-zinc-200 text-black font-heading font-bold rounded-lg transition-all flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed group"
                    >
                      {status.loading ? 'Transmitting...' : 'Execute Payload'}
                      {!status.loading && <Send size={18} className="group-hover:translate-x-1 group-hover:-translate-y-1 transition-transform" />}
                    </button>
                  </form>
                )}
              </div>
            </div>

          </div>
        </div>
      </div>
    </PageTransition>
  );
};

export default Collaboration;

